    function dec2point(num) {
        var split = String(num).split(""."");

        if(num == null || num == undefined){
            return """";
        }
        if(split.length == 1){
            return num.toString() + "".00""; 
        }
        if(split[1].length == 1){
            return split[0] + ""."" + split[1].padEnd(2, ""0"");
        }else{
            return num.toString().match(/^-?\d+(?:\.\d{0,2})?/)[0];
        }
    }


